  it.todo("should kill live cells with fewer than 2 neighbors [(0,1),(1,1)] -> [] (Rule 1: underpopulation)");
  it.todo("should keep a live cell with 2 or 3 neighbors alive (Rule 2: survival)");
  it.todo("should kill a live cell with more than 3 neighbors (Rule 3: overpopulation)");
